    selectedRequest,
    {
        AssignedTo: {
            '@odata.type': "#Microsoft.Azure.Connectors.SharePoint.SPListExpandedUser",
            Claims: "i:0#.f|membership|" & Lower(cmbAssignedTo.Selected.Mail),
            DisplayName: cmbAssignedTo.Selected.DisplayName,
            Email: cmbAssignedTo.Selected.Mail,
            Department: "",
            JobTitle: "",
            Picture: ""
        }
    }
)

Patch(
    Requests,
    selectedRequest,
    {
        Status: { Value: ddStatus.Selected.Value }
    }
)

Patch(
    Requests,
    selectedRequest,
    {
        Department: {
            Id: cmbDepartment.Selected.ID,
            Value: cmbDepartment.Selected.Title
        }
    }
)

Patch(
    Requests,
    selectedRequest,
    {
        ChecklistJson: JSON(colChecklist, JSONFormat.Compact)
    }
)

ClearCollect(
    colChecklist,
    ForAll(
        ParseJSON(selectedRequest.ChecklistJson),
        {
            Title: Text(ThisRecord.Value.Title),
            IsComplete: Boolean(ThisRecord.Value.IsComplete),
            SortOrder: Value(ThisRecord.Value.SortOrder)
        }
    )
)

If(
    FormRequest.Valid && FormDetails.Valid,
    SubmitForm(FormRequest);
    SubmitForm(FormDetails),
    Notify("Please fix the highlighted fields before submitting.", NotificationType.Error)
)

Set(
    selectedRequest,
    Patch(Requests, selectedRequest, { Title: txtTitle.Value })
);
Refresh(Requests);
Set(selectedRequest, LookUp(Requests, ID = selectedRequest.ID))

Set(
    currentUserRole,
    LookUp(AppSecurity, Lower(Email) = Lower(User().Email), Role.Value)
);

btnApprove.Visible = currentUserRole in ["Admin", "Approver"]

Patch(
    Requests,
    selectedRequest,
    {
        RequestStatus: { Value: "Approved" }
    }
)

Set(varEditingRequest, ThisItem);
Set(varShowEditModal, true);
EditForm(frmRequestQuickEdit)

ForAll(
    colChecklist,
    Patch(
        ChecklistItems,
        Coalesce(LookUp(ChecklistItems, ID = ThisRecord.ID), Defaults(ChecklistItems)),
        {
            Title: ThisRecord.Title,
            IsComplete: ThisRecord.IsComplete,
            RequestId: selectedRequest.ID
        }
    )
)

With(
    {
        totalRows: CountRows(colChecklist),
        doneRows: CountRows(Filter(colChecklist, IsComplete))
    },
    Patch(
        Deliverables,
        selectedDeliverable,
        { CompletionPercent: If(totalRows = 0, 0, Round(doneRows / totalRows * 100, 0)) }
    )
)

