Patch(
    Requests,
    Coalesce(selectedRequest, Defaults(Requests)),
    {
        Title: txtTitle.Value,
        RequestStatus: { Value: "Draft" }
    }
)

If(
    !varSaving,
    Set(varSaving, true);
    IfError(
        Patch(Requests, Defaults(Requests), { Title: txtTitle.Value }),
        Notify("Save failed.", NotificationType.Error),
        Notify("Saved.", NotificationType.Success)
    );
    Set(varSaving, false)
)

Patch(
    colEditableRows,
    ThisItem,
    {
        Notes: txtNotes.Value,
        IsDirty: true
    }
);

ForAll(
    Filter(colEditableRows, IsDirty),
    Patch(RequestTasks, LookUp(RequestTasks, ID = ThisRecord.ID), { Notes: ThisRecord.Notes })
)

ForAll(
    colSelectedRequests,
    Patch(
        Requests,
        LookUp(Requests, ID = ThisRecord.ID),
        { RequestStatus: { Value: ddBulkStatus.Selected.Value } }
    )
)

